// Record SLA start (matches the description's Opened time) + IRIS case id.
const bcf = $('Build Case Fields').first().json;
const items = $input.all();

const results = items.map(item => {
  const json = item.json;
  const irisCaseId = json?.data?.case_id || json?.data?.id || json?.case_id;
  return {
    json: {
      ...json,
      offense_id: bcf.offense_id,
      severity: bcf.severity,
      iris_case_id: irisCaseId,
      sla_start: bcf.opened_iso,
      target_hours: bcf.target_hours,
      due_iso: bcf.due_iso,
      sla_status: 'running',
    },
  };
});

try {
  const fs = require('fs');
  const logPath = '/home/node/.n8n/workspace/siem-sla-metrics.jsonl';
  const e = results[0].json;
  const logLine = JSON.stringify({
    case_id: e.iris_case_id, offense_id: e.offense_id, sla_start: e.sla_start,
    severity: e.severity, target_hours: e.target_hours, due: e.due_iso, event: 'sla_started',
  });
  fs.appendFileSync(logPath, logLine + '\n');
} catch (e) {
  results[0].json.sla_file_error = e.message;
}

return results;

// Compute closed timestamp, duration, and SLA met/breached status.
const fs = require('fs');
const webhook = $('Close Webhook').first().json.body;
const caseId = webhook.case_id;
const closeReason = webhook.close_reason || 'resolved';
const logPath = '/home/node/.n8n/workspace/siem-sla-metrics.jsonl';

const pad = n => String(n).padStart(2, '0');
const pretty = d => `${d.getUTCFullYear()}-${pad(d.getUTCMonth()+1)}-${pad(d.getUTCDate())} ${pad(d.getUTCHours())}:${pad(d.getUTCMinutes())}:${pad(d.getUTCSeconds())}`;
const humanize = s => {
  if (s == null) return 'n/a';
  const h = Math.floor(s/3600), m = Math.floor((s%3600)/60), sec = s%60;
  const p = []; if (h) p.push(h+'h'); if (m) p.push(m+'m'); p.push(sec+'s'); return p.join(' ');
};

const now = new Date();
let slaStart = null, targetHours = null, slaDuration = null, status = 'closed';

try {
  const lines = fs.readFileSync(logPath, 'utf8').trim().split('\n');
  for (const line of lines) {
    if (line.trim() === '') continue;
    const entry = JSON.parse(line);
    if (String(entry.case_id) === String(caseId) && entry.event === 'sla_started') {
      slaStart = entry.sla_start; targetHours = entry.target_hours; break;
    }
  }
  if (slaStart) { slaDuration = Math.round((now.getTime() - new Date(slaStart).getTime())/1000); status = 'completed'; }
  else { status = 'closed_no_sla_record'; }
  const closeLog = JSON.stringify({
    case_id: caseId, sla_start: slaStart, sla_end: now.toISOString(),
    sla_duration_seconds: slaDuration, target_hours: targetHours, event: 'sla_closed',
  });
  fs.appendFileSync(logPath, closeLog + '\n');
} catch (e) {
  status = 'closed_log_error';
}

let status_md;
if (slaStart && targetHours != null && slaDuration != null) {
  const targetS = targetHours * 3600;
  if (slaDuration <= targetS) status_md = `✅ **Met** (within ${targetHours}h) · ${closeReason}`;
  else status_md = `❌ **Breached** (${targetHours}h target exceeded by ${humanize(slaDuration - targetS)}) · ${closeReason}`;
} else {
  status_md = `☑️ Closed · ${closeReason}`;
}

const dueDate = (slaStart && targetHours != null)
  ? new Date(new Date(slaStart).getTime() + targetHours * 3600 * 1000) : null;

return [{ json: {
  case_id: caseId, close_reason: closeReason,
  sla_start: slaStart, closed_iso: now.toISOString(), closed_pretty: pretty(now),
  duration_seconds: slaDuration, dur_human: humanize(slaDuration),
  target_hours: targetHours, due_pretty: dueDate ? pretty(dueDate) : null,
  status_md, sla_status: status,
  sla_duration_seconds: slaDuration,
} }];

// Build the passthrough item for the enrichment sub-workflow.
const sla = $input.first().json;
const ef = $('Extract Fields').first().json;
return [{ json: { case_id: sla.iris_case_id, indicator: ef.indicator, indicator_type: ef.indicator_type, source_ip: ef.source_ip } }];

// Compute SLA fields + assemble the markdown case description.
const f = $input.first().json;
const pad = n => String(n).padStart(2, '0');
const pretty = d => `${d.getUTCFullYear()}-${pad(d.getUTCMonth()+1)}-${pad(d.getUTCDate())} ${pad(d.getUTCHours())}:${pad(d.getUTCMinutes())}:${pad(d.getUTCSeconds())}`;

const sev = (f.severity || '').toLowerCase();
const TARGETS = { critical: 4, high: 8, medium: 24, low: 24 };
const target_hours = TARGETS[sev] != null ? TARGETS[sev] : 24;

const now = new Date();
const due = new Date(now.getTime() + target_hours * 3600 * 1000);
const opened_iso = now.toISOString();
const opened_pretty = pretty(now);
const due_iso = due.toISOString();
const due_pretty = pretty(due);

const type = f.type || 'unknown';
const classification = (type === 'malware_c2' || type === 'ransomware_indicator') ? 3
  : ((type === 'lateral_movement' || type === 'privilege_escalation') ? 2 : 1);

const desc = [
  `# 🚨 SIEM Offense: ${type}`,
  ``,
  `${f.description || '_No description provided._'}`,
  ``,
  `## 📌 Detection details`,
  `| Field | Value |`,
  `| --- | --- |`,
  `| **Offense ID** | \`${f.offense_id}\` |`,
  `| **Severity** | \`${f.severity}\` |`,
  `| **Type** | ${type} |`,
  `| **Confidence** | ${f.confidence}% |`,
  `| **Indicator** | \`${f.indicator}\` (${f.indicator_type}) |`,
  `| **Source IP** | \`${f.source_ip}\` |`,
  `| **Affected asset** | ${f.asset_hostname} (\`${f.asset_ip}\`) |`,
  ``,
  `## ⏱️ SLA / Case lifecycle`,
  `| Event | Timestamp |`,
  `| --- | --- |`,
  `| 🟢 **Opened** | ${opened_pretty} UTC |`,
  `| 🔴 **Closed** | _pending — written on close_ |`,
  ``,
  `| SLA metric | Value |`,
  `| --- | --- |`,
  `| **Target (${sev || 'n/a'})** | ${target_hours}h |`,
  `| **Due by** | ${due_pretty} UTC |`,
  `| **Time to resolve** | _pending_ |`,
  `| **Status** | ⏳ Open |`,
  ``,
  `---`,
  `*Threat-intel enrichment (AbuseIPDB · Shodan · OTX) is posted as a note in the **SIEM Enrichment** directory.*`,
].join('\n');

const caseBody = {
  case_name: `[${f.offense_id}] ${type} from ${f.source_ip}`,
  case_description: desc,
  case_soc_id: String(f.offense_id),
  case_customer: 1,
  case_classification: classification,
  custom_tags: `siem,${type},${f.severity}`,
};

return [{ json: { ...f, opened_iso, opened_pretty, target_hours, due_iso, due_pretty, classification, caseBody } }];

// Fill the SLA placeholders in the fetched case description.
const fetched = $('Get Case').first().json;
const sla = $('Calculate SLA Duration').first().json;
let desc = (fetched && fetched.data && fetched.data.case_description) || '';

const closedCell = `| 🔴 **Closed** | ${sla.closed_pretty} UTC |`;
const ttrCell = `| **Time to resolve** | ${sla.dur_human} (${sla.duration_seconds}s) |`;
const statusCell = `| **Status** | ${sla.status_md} |`;

desc = desc
  .replace('| 🔴 **Closed** | _pending — written on close_ |', closedCell)
  .replace('| **Time to resolve** | _pending_ |', ttrCell)
  .replace('| **Status** | ⏳ Open |', statusCell);

return [{ json: { case_id: sla.case_id, case_description: desc } }];
